Recent changes: Added reproduction logic - collects dead cell candidates adjacent to live cells using nested loops and a Map for deduplication, then filters those with exactly 3 live neighbors.

Current implementation:
```typescript
export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const survivors = liveCells.filter((cell) => {
    const neighbors = countNeighbors(cell, liveCells);
    return neighbors === 2 || neighbors === 3;
  });

  const deadCandidates = new Map<string, Cell>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        const key = `${nx},${ny}`;
        if (!deadCandidates.has(key) && !liveCells.some(([lx, ly]) => lx === nx && ly === ny)) {
          deadCandidates.set(key, [nx, ny]);
        }
      }
    }
  }

  const born = [...deadCandidates.values()].filter(
    (cell) => countNeighbors(cell, liveCells) === 3
  );

  return [...survivors, ...born];
};
```

